            :value=\"data.id\"\r\n                        >\r\n                        </el-option>\r\n                    </el-select>\r\n                </div>\r\n                <div class=\"col-md-2 mt-sm-2  mb-sm-1 d-flex align-items-end\">\r\n                    <el-button\r\n                        size=\"mini\"\r\n                        type=\"primary\"\r\n                        icon=\"el-icon-plus\"\r\n                        circle\r\n                        @click=\"addConcept\"\r\n                    ></el-button>\r\n                </div>\r\n                <div\r\n                    class=\"col-md-12 mt-1 table-responsive\"\r\n                    v-if=\"conceptsSelected.length != 0\"\r\n                >\r\n                    <table class=\"table  table-striped table-hover\">\r\n                        <thead>\r\n                            <tr>\r\n                                <th>#</th>\r\n                                <th>Extra</th>\r\n                                <th>Descripción</th>\r\n                                <th>Total</th>\r\n                                <th></th>\r\n                            </tr>\r\n                        </thead>\r\n                        <tbody>\r\n                            <tr\r\n                                v-for=\"(concept, idx) in conceptsSelected\"\r\n                                :key=\"idx\"\r\n                            >\r\n                                <td>{{ idx + 1 }}</td>\r\n                                <td>\r\n                                    {{ concept.generalConcept }}\r\n                                </td>\r\n                                <td>\r\n                                    {{ concept.description }}\r\n                                </td>\r\n                                <td>{{ concept.price }}</td>\r\n                                <td>\r\n                                    <el-button\r\n                                        @click=\"removeConcept(